					'pool' => $pool,
					'selected' => $selected,
					'fatal' => $fatal,
					'method' => __METHOD__
				]
			);
		}

		$model->setHoneypots($selected);
		$model->setFatalHoneypots($fatal);

		return ['displayed' => $selected, 'fatal' => $fatal];
	}

