type Cleanup = ((...a: any) => any) | Promise<(...a: any) => any>;

type Unsub = (...a: any) => any;

interface Executable<N> {
  ex: (n: N | undefined) => Cleanup | any;
}

interface Observable {
  sub: (f: (...a: any) => any) => Unsub | any;
}

type Noop = null | undefined | void;

type Hooks<N> = Observable | Executable<N> | Noop;

const CLEANUPS = new Set<() => boolean>();

const runCleanup =
  "requestIdleCallback" in window
    ? requestIdleCallback
    : (f: () => void) => setTimeout(f, 1);

const Render = <N extends Node>(
  thunk: () => N | Noop,
  hooks: Hooks<N>[],
): N | Noop => {
  let RES: N | Noop;

  runCleanup(() => {
    CLEANUPS.forEach((f) => {
      if (f()) CLEANUPS.delete(f);
    });
  });

  try {
    RES = thunk();
  } catch (err) {
    console.error(err);
    return;
  }

  let executables: Executable<N>[] = [];
  let effectCleanups: Cleanup[] = [];
  let unsubs: Unsub[] = [];

  let RUN_EFFECTS = () => {
    effectCleanups.length = 0;
    for (let i = 0; i < executables.length; i++) {
      try {
        const f = executables[i]!.ex(RES ?? undefined);
        if (typeof f === "function" || f instanceof Promise) {
          effectCleanups.push(f);
        }
      } catch (err) {
        console.error(err);
      }
    }
  };

  let RENDER = () => {
    requestAnimationFrame(() => {
      if (typeof thunk !== "function") return;
      try {
        const next = thunk();
        if (next instanceof Node && RES instanceof Node && RES.parentNode) {
          RES.parentNode.replaceChild(next, RES);
        }
        RES = next;
      } catch (err) {
        console.error(err);
      }
      queueMicrotask(RUN_EFFECTS);
    });
  };

  for (let i = 0; i < hooks.length; i++) {
    const h = hooks[i]!;
    if ("sub" in h && typeof h.sub === "function") {
      const unsub = h.sub(RENDER);
      if (typeof unsub === "function") unsubs.push(unsub);
    } else if ("ex" in h && typeof h.ex === "function") {
      executables.push(h);
    }
  }

  CLEANUPS.add(() => {
    if (!RES?.isConnected) {
      for (let i = 0; i < unsubs.length; i++) {
        try {
          unsubs[i]!();
        } catch (err) {
          console.error(err);
        }
      }

      for (let i = 0; i < effectCleanups.length; i++) {
        try {
          const f = effectCleanups[i]!;
          if (f instanceof Promise) {
            f.then((f) => f());
          } else {
            f();
          }
        } catch (err) {
          console.error(err);
        }
      }

      RES = void 0 as never;
      RENDER = void 0 as never;
      RUN_EFFECTS = void 0 as never;
      thunk = void 0 as never;
      hooks = void 0 as never;
      executables = void 0 as never;
      effectCleanups = void 0 as never;
      unsubs = void 0 as never;
      return true;
    } else {
      return false;
    }
  });

  queueMicrotask(RUN_EFFECTS);

  return RES;
};

export { Render, type FC };
