private Color RandomColor(int min = 0, int max = 255)
{
    return Color.FromArgb(
        255,
        _rand.Next(min, max + 1),
        _rand.Next(min, max + 1),
        _rand.Next(min, max + 1));
}

private Color RandomVibrantColor()
{
    // Generate a vibrant color with high saturation and brightness via HSV conversion
    double hue = _rand.NextDouble() * 360; // Hue between 0-360
    double saturation = _rand.NextDouble() * 0.5 + 0.5; // Saturation between 0.5-1.0
    double value = _rand.NextDouble() * 0.5 + 0.7;      // Brightness between 0.7-1.0
    return ColorFromHSV(hue, saturation, value);
}

private Color ColorFromHSV(double hue, double saturation, double value)
{
    int hi = Convert.ToInt32(Math.Floor(hue / 60)) % 6;
    double f = hue / 60 - Math.Floor(hue / 60);

    value = Math.Max(0, Math.Min(1, value));       // clamp value to [0,1]
    saturation = Math.Max(0, Math.Min(1, saturation)); // clamp saturation to [0,1]
    hue = hue % 360;                               // hue in [0,360)

    int v = Clamp((int)(value * 255), 0, 255);
    int p = Clamp((int)(v * (1 - saturation)), 0, 255);
    int q = Clamp((int)(v * (1 - f * saturation)), 0, 255);
    int t = Clamp((int)(v * (1 - (1 - f) * saturation)), 0, 255);

    return hi switch
    {
        0 => Color.FromArgb(255, v, t, p),
        1 => Color.FromArgb(255, q, v, p),
        2 => Color.FromArgb(255, p, v, t),
        3 => Color.FromArgb(255, p, q, v),
        4 => Color.FromArgb(255, t, p, v),
        _ => Color.FromArgb(255, v, p, q),
    };
}

private Color DarkenColor(Color color, float factor)
{
    int r = (int)(color.R * (1 - factor));
    int g = (int)(color.G * (1 - factor));
    int b = (int)(color.B * (1 - factor));
    return Color.FromArgb(255, Clamp(r, 0, 255), Clamp(g, 0, 255), Clamp(b, 0, 255));
}

private int Clamp(int val, int min, int max) => val < min ? min : (val > max ? max : val);

